// Defines the possible positions where the Drawer component can be placed, such as left, right, top, or bottom of the screen.
export type Placement = 'left' | 'right' | 'top' | 'bottom';
// Specifies the predefined size options for the Drawer, ranging from extra small (xs) to full width/height.
export type Size = 'xs' | 'sm' | 'md' | 'lg' | 'xl' | 'full';
// Determines the placement of the close button within the Drawer, allowing it to be on the left, right, or hidden entirely.
export type CloseButtonPosition = 'left' | 'right' | 'none';
